import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)
bp = {p['id']: p['resolvedVersion'] for p in b['projects'][0]['frameworks'][0]['topLevelPackages']}
ap = {p['id']: p['resolvedVersion'] for p in a['projects'][0]['frameworks'][0]['topLevelPackages']}
if bp == ap: print('All packages resolve to identical versions.')
else:
    for k in set(list(bp.keys())+list(ap.keys())):
        if bp.get(k) != ap.get(k): print(f'CHANGED: {k} {bp.get(k)} -> {ap.get(k)}')
"

